from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build a graph of all entities and their relationships
    entity_triples = {}
    for t in triples:
        if t.subject not in entity_triples:
            entity_triples[t.subject] = []
        entity_triples[t.subject].append(t)

    # Find the main building (most triples or contains building-related predicates)
    building_keywords = ["architect", "buildingStartDate", "floorCount", "cost", "floorArea",
                         "height", "owner", "tenant", "buildingType", "architecturalStyle",
                         "completionDate", "inaugurationDate", "developer", "address", "location"]

    main_subject = None
    max_score = 0
    for subject, subject_triples in entity_triples.items():
        score = len(subject_triples)
        for t in subject_triples:
            if t.predicate in building_keywords:
                score += 1
        if score > max_score:
            max_score = score
            main_subject = subject

    main_triples = entity_triples[main_subject] if main_subject else []

    # Collect all information about the main building and related entities
    sentence_parts = []
    processed_entities = {main_subject}

    # Start building the sentence
    type_triple = next((t for t in main_triples if t.predicate == "buildingType"), None)
    if type_triple:
        sentence_parts.append(f"{main_subject} is a {type_triple.object}")
    else:
        sentence_parts.append(main_subject)

    # Add architect/style information
    architect = next((t for t in main_triples if t.predicate == "architect"), None)
    style = next((t for t in main_triples if t.predicate == "architecturalStyle"), None)
    if architect or style:
        design_info = []
        if architect:
            design_info.append(f"designed by {architect.object}")
        if style:
            design_info.append(f"in {style.object} style")
        sentence_parts.append(f", {', '.join(design_info)}")

    # Add construction details
    height = next((t for t in main_triples if t.predicate == "height"), None)
    floors = next((t for t in main_triples if t.predicate == "floorCount"), None)
    cost = next((t for t in main_triples if t.predicate == "cost"), None)
    area = next((t for t in main_triples if t.predicate == "floorArea"), None)
    start_date = next((t for t in main_triples if t.predicate in ["buildingStartDate", "yearOfConstruction"]), None)
    completion = next((t for t in main_triples if t.predicate == "completionDate"), None)
    inauguration = next((t for t in main_triples if t.predicate == "inaugurationDate"), None)

    if height or floors or cost or area or start_date or completion or inauguration:
        const_info = []
        if height:
            const_info.append(f"measuring {height.object} tall")
        if floors:
            const_info.append(f"with {floors.object} floors")
        if cost:
            const_info.append(f"at a cost of {cost.object}")
        if area:
            const_info.append(f"covering {area.object} floor area")
        if start_date:
            const_info.append(f"built in {start_date.object}")
        if completion:
            const_info.append(f"completed in {completion.object}")
        if inauguration:
            const_info.append(f"inaugurated on {inauguration.object}")
        if const_info:
            sentence_parts.append(f", {', '.join(const_info)}")

    # Add location and related entity information
    location = next((t for t in main_triples if t.predicate == "location"), None)
    address = next((t for t in main_triples if t.predicate == "address"), None)
    country_triple = next((t for t in main_triples if t.predicate == "country"), None)
    state = next((t for t in main_triples if t.predicate == "state"), None)
    region = next((t for t in main_triples if t.predicate == "region"), None)
    is_part_of = next((t for t in main_triples if t.predicate == "isPartOf"), None)

    loc_info = []
    if address:
        loc_info.append(f"located at {address.object}")
    elif location:
        loc_info.append(f"located at {location.object}")
    elif state:
        loc_info.append(f"located in {state.object}")
    elif region:
        loc_info.append(f"located in the region of {region.object}")
    elif is_part_of:
        loc_info.append(f"part of {is_part_of.object}")

    # Check for country information in related entities
    if country_triple:
        country = country_triple.object
        loc_info.append(f"in {country}")
        # Check for capital of this country
        if country in entity_triples:
            capital = next((t for t in entity_triples[country] if t.predicate == "capital"), None)
            if capital:
                sentence_parts.append(f" in {country}, where the capital is {capital.object}")
            else:
                sentence_parts.append(f" in {country}")
    elif loc_info:
        sentence_parts.append(f", {', '.join(loc_info)}")

    # Add other building attributes
    owner = next((t for t in main_triples if t.predicate == "owner"), None)
    developer = next((t for t in main_triples if t.predicate == "developer"), None)
    tenant = next((t for t in main_triples if t.predicate == "tenant"), None)
    current_tenants = next((t for t in main_triples if t.predicate == "currentTenants"), None)
    former_name = next((t for t in main_triples if t.predicate == "formerName"), None)

    if owner or developer or tenant or current_tenants or former_name:
        attr_info = []
        if former_name:
            attr_info.append(f"formerly known as {former_name.object}")
        if owner:
            attr_info.append(f"owned by {owner.object}")
        if developer:
            attr_info.append(f"developed by {developer.object}")
        if tenant:
            attr_info.append(f"tenanted by {tenant.object}")
        if current_tenants:
            attr_info.append(f"with current tenants {current_tenants.object}")
        if attr_info:
            sentence_parts.append(f", {', '.join(attr_info)}")

    # Join parts into a single sentence
    sentence = ''.join(sentence_parts)

    # Ensure proper capitalization and punctuation
    if sentence:
        sentence = sentence[0].upper() + sentence[1:]
        if not sentence.endswith('.'):
            sentence += '.'

    return sentence

# EVOLVE-BLOCK-END
